from semantic_kernel.functions import kernel_function
import json

class FinancePlugin:
    """Functions for working with financial data."""

    @kernel_function(
        name="GetStockPrice",
        description="Return the latest price for a stock ticker symbol.",
    )
    def get_stock_price(self, ticker: str) -> str:
        # Stub — replace with a real market data API call
        prices = {"MSFT": 420.50, "AAPL": 195.80, "GOOG": 175.30}
        price = prices.get(ticker.upper(), "unknown")
        return json.dumps({"ticker": ticker.upper(), "price": price, "currency": "USD"})

    @kernel_function(
        name="CalculateReturn",
        description="Calculate percentage return from buy_price to sell_price.",
    )
    def calculate_return(self, buy_price: float, sell_price: float) -> str:
        pct = (sell_price - buy_price) / buy_price * 100
        return f"{pct:.2f}% return"

kernel.add_plugin(FinancePlugin(), plugin_name="Finance")

# Call directly
async def demo():
    result = await kernel.invoke(
        kernel.plugins["Finance"]["GetStockPrice"],
        ticker="MSFT",
    )
    print(result)

asyncio.run(demo())
